--
-- Name: audit_issue_taxonomy(); Type: FUNCTION; Schema: kirana_kart; Owner: orguser
--

CREATE FUNCTION kirana_kart.audit_issue_taxonomy() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN

    IF TG_OP = 'INSERT' THEN
        INSERT INTO kirana_kart.issue_taxonomy_audit
        (issue_id, issue_code, action_type, new_data, changed_by)
        VALUES
        (NEW.id, NEW.issue_code, 'CREATE', to_jsonb(NEW), current_user);

        RETURN NEW;

    ELSIF TG_OP = 'UPDATE' THEN
        INSERT INTO kirana_kart.issue_taxonomy_audit
        (issue_id, issue_code, action_type, old_data, new_data, changed_by)
        VALUES
        (NEW.id, NEW.issue_code, 'UPDATE', to_jsonb(OLD), to_jsonb(NEW), current_user);

        RETURN NEW;

    END IF;

    RETURN NULL;
END;
$$;


ALTER FUNCTION kirana_kart.audit_issue_taxonomy() OWNER TO orguser;

--
-- Name: create_taxonomy_snapshot(character varying); Type: FUNCTION; Schema: kirana_kart; Owner: orguser
--

CREATE FUNCTION kirana_kart.create_taxonomy_snapshot(p_label character varying) RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE
    existing_count INT;
BEGIN
    SELECT COUNT(*) INTO existing_count
    FROM kirana_kart.issue_taxonomy_versions
    WHERE version_label = p_label;

    IF existing_count > 0 THEN
        RAISE EXCEPTION 'Snapshot version already exists: %', p_label;
    END IF;

    INSERT INTO kirana_kart.issue_taxonomy_versions
    (version_label, created_by, snapshot_data)
    VALUES
    (
        p_label,
        current_user,
        (SELECT jsonb_agg(t) FROM kirana_kart.issue_taxonomy t)
    );
END;
$$;


ALTER FUNCTION kirana_kart.create_taxonomy_snapshot(p_label character varying) OWNER TO orguser;

--
-- Name: fn_get_active_kb(); Type: FUNCTION; Schema: kirana_kart; Owner: orguser
--

CREATE FUNCTION kirana_kart.fn_get_active_kb() RETURNS jsonb
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_active VARCHAR;
    v_snapshot JSONB;
BEGIN
    SELECT active_version
    INTO v_active
    FROM kirana_kart.kb_runtime_config
    ORDER BY activated_at DESC
    LIMIT 1;

    SELECT snapshot_data
    INTO v_snapshot
    FROM kirana_kart.knowledge_base_versions
    WHERE version_label = v_active;

    RETURN v_snapshot;
END;
$$;


ALTER FUNCTION kirana_kart.fn_get_active_kb() OWNER TO orguser;

--
-- Name: fn_insert_kb_draft(jsonb, jsonb, character varying); Type: FUNCTION; Schema: kirana_kart; Owner: orguser
--

CREATE FUNCTION kirana_kart.fn_insert_kb_draft(p_document jsonb, p_chunks jsonb, p_user character varying) RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_document_id VARCHAR;
    v_version VARCHAR;
BEGIN
    v_document_id := p_document->>'document_id';
    v_version := p_document->>'version';

    -- Insert draft document
    INSERT INTO kirana_kart.knowledge_base_drafts (
        document_id,
        title,
        domain,
        category,
        subcategory,
        content,
        risk_level,
        auto_resolution_allowed,
        escalation_required,
        linked_issue_codes,
        version_label,
        created_at,
        updated_at
    )
    VALUES (
        v_document_id,
        p_document->>'title',
        p_document->>'domain',
        p_document->>'category',
        p_document->>'subcategory',
        p_document::TEXT,
        p_document->>'risk_level',
        (p_document->>'auto_resolution_allowed')::BOOLEAN,
        (p_document->>'escalation_required')::BOOLEAN,
        ARRAY(SELECT jsonb_array_elements_text(p_document->'linked_issue_codes')),
        v_version,
        CURRENT_TIMESTAMP,
        CURRENT_TIMESTAMP
    );

    -- Insert chunks
    INSERT INTO kirana_kart.knowledge_base_chunks_drafts (
        document_id,
        chunk_id,
        title,
        content,
        domain,
        category,
        subcategory,
        risk_level,
        auto_resolution_allowed,
        escalation_required,
        linked_issue_codes,
        version_label
    )
    SELECT
        v_document_id,
        chunk->>'chunk_id',
        chunk->>'title',
        chunk->>'content',
        p_document->>'domain',
        p_document->>'category',
        p_document->>'subcategory',
        p_document->>'risk_level',
        (p_document->>'auto_resolution_allowed')::BOOLEAN,
        (p_document->>'escalation_required')::BOOLEAN,
        ARRAY(SELECT jsonb_array_elements_text(p_document->'linked_issue_codes')),
        v_version
    FROM jsonb_array_elements(p_chunks) AS chunk;

    -- Audit log
    INSERT INTO kirana_kart.knowledge_base_audit (
        action_type,
        document_id,
        version_label,
        changed_by,
        old_value,
        new_value
    )
    VALUES (
        'add',
        v_document_id,
        v_version,
        p_user,
        NULL,
        p_document
    );

END;
$$;


ALTER FUNCTION kirana_kart.fn_insert_kb_draft(p_document jsonb, p_chunks jsonb, p_user character varying) OWNER TO orguser;

--
-- Name: fn_publish_kb_version(character varying, character varying); Type: FUNCTION; Schema: kirana_kart; Owner: orguser
--

CREATE FUNCTION kirana_kart.fn_publish_kb_version(p_version_label character varying, p_user character varying) RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_snapshot JSONB;
BEGIN
    -- Collect full snapshot of this version
    SELECT jsonb_agg(to_jsonb(d))
    INTO v_snapshot
    FROM kirana_kart.knowledge_base_drafts d
    WHERE d.version_label = p_version_label;

    IF v_snapshot IS NULL THEN
        RAISE EXCEPTION 'No drafts found for version %', p_version_label;
    END IF;

    -- Insert immutable snapshot
    INSERT INTO kirana_kart.knowledge_base_versions (
        version_label,
        status,
        created_by,
        snapshot_data
    )
    VALUES (
        p_version_label,
        'published',
        p_user,
        v_snapshot
    );

    -- Update runtime active version
    INSERT INTO kirana_kart.kb_runtime_config (
        active_version,
        activated_at
    )
    VALUES (
        p_version_label,
        CURRENT_TIMESTAMP
    );

    -- Create vector job
    INSERT INTO kirana_kart.kb_vector_jobs (
        version_label,
        status
    )
    VALUES (
        p_version_label,
        'pending'
    );

    -- Audit
    INSERT INTO kirana_kart.knowledge_base_audit (
        action_type,
        version_label,
        changed_by,
        old_value,
        new_value
    )
    VALUES (
        'publish',
        p_version_label,
        p_user,
        NULL,
        v_snapshot
    );

END;
$$;


ALTER FUNCTION kirana_kart.fn_publish_kb_version(p_version_label character varying, p_user character varying) OWNER TO orguser;

--
-- Name: fn_rollback_kb_version(character varying, character varying); Type: FUNCTION; Schema: kirana_kart; Owner: orguser
--

CREATE FUNCTION kirana_kart.fn_rollback_kb_version(p_target_version character varying, p_user character varying) RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- Ensure version exists
    IF NOT EXISTS (
        SELECT 1 FROM kirana_kart.knowledge_base_versions
        WHERE version_label = p_target_version
    ) THEN
        RAISE EXCEPTION 'Version % does not exist', p_target_version;
    END IF;

    -- Activate target version
    INSERT INTO kirana_kart.kb_runtime_config (
        active_version,
        activated_at
    )
    VALUES (
        p_target_version,
        CURRENT_TIMESTAMP
    );

    -- Audit
    INSERT INTO kirana_kart.knowledge_base_audit (
        action_type,
        version_label,
        changed_by
    )
    VALUES (
        'rollback',
        p_target_version,
        p_user
    );

END;
$$;


ALTER FUNCTION kirana_kart.fn_rollback_kb_version(p_target_version character varying, p_user character varying) OWNER TO orguser;

--
-- Name: fn_update_vector_job_status(character varying, character varying, text); Type: FUNCTION; Schema: kirana_kart; Owner: orguser
--

CREATE FUNCTION kirana_kart.fn_update_vector_job_status(p_version character varying, p_status character varying, p_error text DEFAULT NULL::text) RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
    UPDATE kirana_kart.kb_vector_jobs
    SET
        status = p_status,
        started_at = CASE WHEN p_status = 'running' THEN CURRENT_TIMESTAMP ELSE started_at END,
        completed_at = CASE WHEN p_status IN ('completed','failed') THEN CURRENT_TIMESTAMP ELSE completed_at END,
        error = p_error
    WHERE version_label = p_version;
END;
$$;


ALTER FUNCTION kirana_kart.fn_update_vector_job_status(p_version character varying, p_status character varying, p_error text) OWNER TO orguser;

